(()=>{"use strict";chrome.runtime.onConnect.addListener(e=>{"translate"===e.name&&e.onMessage.addListener(async t=>{if("TRANSLATE"===t.type)try{const{apiKey:s,prompt:o}=await chrome.storage.sync.get(["apiKey","prompt"]);if(!s)return void e.postMessage({type:"ERROR",message:"请先点击扩展图标，在设置中配置 DeepSeek API Key"});const a=await fetch("https://api.deepseek.com/chat/completions",{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${s}`},body:JSON.stringify({model:"deepseek-chat",messages:[{role:"system",content:o||"你是一个简洁的帮忙翻译并解释的助手，需要对收到的内容做翻译并简要解释，回复内容为以下两个部分：\n一、翻译结果(有以下情况)：\n  1.当收到一个英文单词时，给出这个单词的几个常见中文翻译，并给出这个单词的词性，常见用法等简要解释；\n  2.当收到几个单词或者一段句子时需要帮我翻译文本；\n  3.收到例如stackName或data.length或其他格式的英文文本时，也需要翻译为中文；\n  4.当收到的文本很长很长时，只需要帮我翻译文本的摘要，不需要翻译全文。\n二、简要解释\n输出格式：第一行给出翻译结果，空一行后给出简要解释（用中文）（收到的文本是什么，什么作用等等），做个简要介绍，保持简短精炼。"},{role:"user",content:t.text}],stream:!0,temperature:.3,max_tokens:500})});if(!a.ok){const t=await a.text();return void e.postMessage({type:"ERROR",message:`API 请求失败 (${a.status}): ${t}`})}const n=a.body?.getReader();if(!n)return void e.postMessage({type:"ERROR",message:"无法读取响应"});const r=new TextDecoder;let c="";for(;;){const{done:t,value:s}=await n.read();if(t)break;c+=r.decode(s,{stream:!0});const o=c.split("\n");c=o.pop()||"";for(const t of o){const s=t.trim();if(!s.startsWith("data: "))continue;const o=s.slice(6);if("[DONE]"===o)return void e.postMessage({type:"DONE"});try{const t=JSON.parse(o),s=t.choices?.[0]?.delta?.content;s&&e.postMessage({type:"CHUNK",content:s})}catch{}}}e.postMessage({type:"DONE"})}catch(t){const s=t instanceof Error?t.message:"未知错误";e.postMessage({type:"ERROR",message:`翻译出错: ${s}`})}})})})();